import { BITFAB_SKILLS } from "../skills.js";
const SKILL_PATTERN = new RegExp(`^\\s*\\/bitfab[:-](?<skill>${BITFAB_SKILLS.join("|")})(?=\\s|$)`, "i");
export function extractSkillFromPrompt(prompt) {
    const match = prompt.match(SKILL_PATTERN);
    const raw = match?.groups?.skill?.toLowerCase();
    return BITFAB_SKILLS.includes(raw ?? "")
        ? raw
        : null;
}
